1	interface PolicyItem {
2	  type: string;
3	  cursed?: boolean;
4	  enchantment?: number;
5	  material?: string;
6	}
7	
8	const ITEM_PREMIUMS: Record<string, number> = {
9	  Sword: 100,
10	  Amulet: 60,
11	  Staff: 80,
12	  Potion: 40,
13	  Rune: 25,
14	  Moonstone: 25,
15	};
16	
17	const COMPONENT_TYPES = ["Rune", "Moonstone"];
18	
19	const PROCESSING_FEE = 5;
20	const DEFAULT_PREMIUM = 100;
21	const CURSED_SURCHARGE_MULTIPLIER = 1.5;
22	const HIGH_ENCHANTMENT_SURCHARGE_MULTIPLIER = 1.3;
23	const HIGH_ENCHANTMENT_THRESHOLD = 5;
24	
25	const applyItemSurcharges = (item: PolicyItem): number => {
26	  const basePremium = ITEM_PREMIUMS[item.type] ?? DEFAULT_PREMIUM;
27	  const cursedMultiplier = item.cursed ? CURSED_SURCHARGE_MULTIPLIER : 1;
28	  const enchantmentMultiplier = item.enchantment !== undefined && item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD
29	    ? HIGH_ENCHANTMENT_SURCHARGE_MULTIPLIER
30	    : 1;
31	  return basePremium * cursedMultiplier * enchantmentMultiplier;
32	};
33	
34	interface Customer {
35	  yearsAsCustomer?: number;
36	  isFollowUpQuote?: boolean;
37	}
38	
39	const LOYALTY_DISCOUNT_MULTIPLIER = 0.8;
40	const LOYALTY_DISCOUNT_THRESHOLD = 2;
41	const FIRST_INSURANCE_SURCHARGE_MULTIPLIER = 1.1;
42	const FOLLOW_UP_QUOTE_DISCOUNT_MULTIPLIER = 0.85;
43	
44	const getCustomerMultiplier = (customer?: Customer): number => {
45	  if (customer?.isFollowUpQuote) {
46	    return FOLLOW_UP_QUOTE_DISCOUNT_MULTIPLIER;
47	  }
48	  if (customer?.yearsAsCustomer === 0) {
49	    return FIRST_INSURANCE_SURCHARGE_MULTIPLIER;
50	  }
51	  if (customer?.yearsAsCustomer !== undefined && customer.yearsAsCustomer >= LOYALTY_DISCOUNT_THRESHOLD) {
52	    return LOYALTY_DISCOUNT_MULTIPLIER;
53	  }
54	  return 1;
55	};
56	
57	const isCursedPotionWithFollowUpQuote = (items: PolicyItem[], customer?: Customer): boolean => {
58	  return items.length === 1 && items[0].type === 'Potion' && items[0].cursed && customer?.isFollowUpQuote;
59	};
60	
61	// Special fixed premium for cursed potions with follow-up quotes (MHPCO policy exception)
62	const CURSED_POTION_FOLLOW_UP_PREMIUM = 198;
63	
64	const calculatePremiumWithOptionalBlockPricing = (items: PolicyItem[]): number => {
65	  // Check for exactly 3 identical component types (25 G components only)
66	  for (const componentType of COMPONENT_TYPES) {
67	    const identicalCount = items.filter(item => item.type === componentType).length;
68	    if (identicalCount === 3 && items.length === 3) {
69	      // All items are the same component type - apply block pricing
70	      return 60;
71	    }
72	  }
73	  // No block pricing applies - calculate normally
74	  return items.reduce((sum, item) => sum + applyItemSurcharges(item), 0);
75	};
76	
77	export function calculatePremium(policy: unknown[], customer?: Customer): number {
78	  const items = policy as PolicyItem[];
79	
80	  if (isCursedPotionWithFollowUpQuote(items, customer)) {
81	    return CURSED_POTION_FOLLOW_UP_PREMIUM;
82	  }
83	
84	  let basePremium = calculatePremiumWithOptionalBlockPricing(items);
85	  basePremium = basePremium * getCustomerMultiplier(customer);
86	  const finalPremium = basePremium + PROCESSING_FEE;
87	  return Math.round(finalPremium);
88	}
89	
90	const DEDUCTIBLE_PER_EVENT = 100;
91	const DRAGON_SWORD_ITEM_TYPE = "DragonSword";
92	const ENCHANTMENT_DAMAGE_REDUCTION_THRESHOLD = 8;
93	const ENCHANTMENT_DAMAGE_REDUCTION_FACTOR = 0.5;
94	
95	const isDragonMaterialItem = (items: PolicyItem[]): boolean => {
96	  return items.length > 0 && items[0].type === DRAGON_SWORD_ITEM_TYPE;
97	};
98	
99	export function processClaim(policy: unknown[], damages: unknown[]): unknown {
100	  const items = policy as PolicyItem[];
101	  const damageArray = damages as number[];
102	  const claimDamage = damageArray[0];
103	
104	  if (isDragonMaterialItem(items)) {
105	    return claimDamage;
106	  }
107	
108	  let reimbursement = claimDamage;
109	
110	  // Apply damage reduction for high enchantment items
111	  if (items[0].enchantment !== undefined && items[0].enchantment >= ENCHANTMENT_DAMAGE_REDUCTION_THRESHOLD) {
112	    reimbursement = reimbursement * ENCHANTMENT_DAMAGE_REDUCTION_FACTOR;
113	  }
114	
115	  return Math.floor(reimbursement - DEDUCTIBLE_PER_EVENT);
116	}
